import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Grid,
  Paper,
  Typography,
  Card,
  CardContent,
  IconButton,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Chip,
  useTheme,
  LinearProgress,
  CircularProgress,
} from '@mui/material';
import {
  Search as SearchIcon,
  CalendarToday as CalendarIcon,
  PieChart as PieChartIcon,
  ReceiptLong as ReceiptIcon,
  ShoppingBag as ShoppingIcon,
  TrendingUp as TrendingUpIcon,
  PlayArrow as PlayArrowIcon,
} from '@mui/icons-material';
import StatCard from '../components/common/StatCard';

function Dashboard() {
  const navigate = useNavigate();
  const theme = useTheme();
  const [loading, setLoading] = useState(false);

  // Sample data for the dashboard
  const statCards = [
    {
      title: "Customers",
      value: "5,896",
      icon: <PieChartIcon />,
      color: theme.palette.primary.main,
    },
    {
      title: "Income",
      value: "$100,098",
      icon: <TrendingUpIcon />,
      color: theme.palette.primary.main,
    },
    {
      title: "Products Sold",
      value: "89,878",
      icon: <ShoppingIcon />,
      color: theme.palette.primary.main,
    },
  ];

  const recentOrders = [
    {
      id: "#96865968",
      product: "iPad pro 456gb",
      date: "Aug 30, 2023",
      price: "$4345",
      status: "Delivered"
    },
    {
      id: "#96865968",
      product: "iPad pro mini 512gb",
      date: "Sep 01, 2023",
      price: "$236",
      status: "Canceled"
    },
    {
      id: "#96865968",
      product: "MacBook Air M2",
      date: "Aug 25, 2023",
      price: "$1345",
      status: "Delivered"
    },
    {
      id: "#96865968",
      product: "AirPods Pro 2",
      date: "Sep 02, 2023",
      price: "$249",
      status: "Pending"
    },
  ];

  const getStatusColor = (status) => {
    switch (status) {
      case 'Delivered':
        return {
          color: '#34D399',
          bgColor: 'rgba(52, 211, 153, 0.1)',
        };
      case 'Canceled':
        return {
          color: '#F87171',
          bgColor: 'rgba(248, 113, 113, 0.1)',
        };
      case 'Pending':
        return {
          color: '#FBBF24',
          bgColor: 'rgba(251, 191, 36, 0.1)',
        };
      default:
        return {
          color: theme.palette.text.primary,
          bgColor: 'rgba(0, 0, 0, 0.05)',
        };
    }
  };

  return (
    <Box>
      <Typography variant="h4" fontWeight={600} mb={3}>
        Business Dashboard
      </Typography>

      {/* Stats Cards */}
      <Grid container spacing={3}>
        {statCards.map((card, index) => (
          <Grid item xs={12} sm={4} key={index}>
            <StatCard
              title={card.title}
              value={card.value}
              icon={card.icon}
              color={card.color}
            />
          </Grid>
        ))}
      </Grid>

      {/* Marketplace Section */}
      <Typography variant="h5" fontWeight={600} mt={4} mb={3}>
        Marketplace
      </Typography>

      <Grid container spacing={3}>
        {/* Data Analytics Overview */}
        <Grid item xs={12} md={8}>
          <Card sx={{ borderRadius: 3, height: '100%' }}>
            <CardContent sx={{ p: 3, height: '100%' }}>
              <Grid container spacing={2}>
                <Grid item xs={8}>
                  <Typography variant="h6" fontWeight={600} mb={1}>
                    Data Analytics Overview
                  </Typography>
                  <Typography variant="body2" color="text.secondary" mb={2}>
                    See how your account grow and how you can boost it.
                  </Typography>
                </Grid>
                <Grid item xs={4} sx={{ display: 'flex', justifyContent: 'flex-end', alignItems: 'center' }}>
                  <Box
                    sx={{
                      width: 70,
                      height: 70,
                      borderRadius: '50%',
                      border: `2px solid ${theme.palette.primary.main}`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    <Typography 
                      variant="button" 
                      fontWeight={600} 
                      color="primary"
                      sx={{ fontSize: '0.8rem' }}
                    >
                      START
                    </Typography>
                  </Box>
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Grid>

        {/* Finance Flow */}
        <Grid item xs={12} md={8}>
          <Card sx={{ borderRadius: 3 }}>
            <CardContent sx={{ p: 3 }}>
              <Typography variant="h6" fontWeight={600} mb={1}>
                Finance Flow
              </Typography>
              <Typography variant="h5" fontWeight={600} mb={2}>
                $2,908
              </Typography>
              <Typography variant="body2" color="text.secondary" mb={2}>
                August 2023
              </Typography>

              {/* Simple bar chart visualization */}
              <Box sx={{ mt: 2, display: 'flex', alignItems: 'flex-end', height: 100, gap: 1 }}>
                {Array.from({ length: 31 }, (_, i) => (
                  <Box 
                    key={i}
                    sx={{ 
                      height: `${Math.max(10, Math.random() * 100)}%`, 
                      width: 4, 
                      backgroundColor: i === 20 ? theme.palette.primary.main : 'rgba(0,0,0,0.1)',
                      borderRadius: 1
                    }}
                  />
                ))}
              </Box>
            </CardContent>
          </Card>
        </Grid>

        {/* Upgrade to Pro */}
        <Grid item xs={12} md={4}>
          <Card 
            sx={{ 
              borderRadius: 3, 
              height: '100%', 
              display: 'flex', 
              flexDirection: 'column',
              justifyContent: 'center',
              alignItems: 'center',
              p: 3
            }}
          >
            <Typography variant="h6" fontWeight={600} color="primary" align="center">
              Upgrade to PRO
            </Typography>
            
            <Typography variant="h4" fontWeight={700} align="center" mt={2}>
              $29/mo
            </Typography>
            
            <Typography variant="body2" color="text.secondary" align="center" mt={1} mb={3}>
              100% insurance for your goods
            </Typography>
            
            <Button 
              variant="contained" 
              color="primary" 
              size="large" 
              fullWidth
              sx={{ 
                py: 1.5, 
                borderRadius: 2, 
                textTransform: 'none', 
                fontWeight: 600 
              }}
            >
              Upgrade
            </Button>
          </Card>
        </Grid>
      </Grid>

      {/* Recent Orders */}
      <Box mt={4} mb={2} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h5" fontWeight={600}>
          Recent Orders
        </Typography>
        <Button 
          color="inherit" 
          sx={{ fontWeight: 500, textTransform: 'none' }}
          onClick={() => navigate('/transactions')}
        >
          SEE ALL
        </Button>
      </Box>
      
      <TableContainer component={Paper} sx={{ boxShadow: 'none', borderRadius: 3 }}>
        <Table sx={{ minWidth: 650 }}>
          <TableHead>
            <TableRow>
              <TableCell>Order ID</TableCell>
              <TableCell>Product</TableCell>
              <TableCell>Date</TableCell>
              <TableCell>Price</TableCell>
              <TableCell>Status</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {recentOrders.map((order, index) => {
              const statusStyle = getStatusColor(order.status);
              return (
                <TableRow key={index}>
                  <TableCell sx={{ color: theme.palette.text.secondary }}>
                    {order.id}
                  </TableCell>
                  <TableCell>
                    <Typography fontWeight={500}>{order.product}</Typography>
                  </TableCell>
                  <TableCell sx={{ color: theme.palette.text.secondary }}>
                    {order.date}
                  </TableCell>
                  <TableCell>
                    <Typography fontWeight={500}>{order.price}</Typography>
                  </TableCell>
                  <TableCell>
                    <Chip
                      label={order.status}
                      sx={{
                        color: statusStyle.color,
                        backgroundColor: statusStyle.bgColor,
                        borderRadius: 1,
                        fontWeight: 500,
                      }}
                    />
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
}

export default Dashboard;
